#include <stdio.h>
#include <string.h>
#define MAX 100
int main() {
    int n;
    scanf("%d", &n);
    char command[MAX], directory[MAX];
    char currentDir[MAX] = "/";
    for (int i = 0; i < n; i++) {
        scanf("%s", command);
        if (strcmp(command, "cd") == 0) {
            scanf("%s", directory);
            if (strcmp(directory, "..") == 0) {
                int len = strlen(currentDir);
                currentDir[len - 1] = '\0';
                for (int j = len - 2; j >= 0; j--) {
                    if (currentDir[j] == '/') {
                        currentDir[j] = '\0';
                        break;
                    }
                }
            } else {
                strcat(currentDir, directory);
                strcat(currentDir, "/");
            }
        } else if (strcmp(command, "pwd") == 0) {
            printf("%s\n", currentDir);
        }
    }
    return 0;
}

